public static client void main(Args _args)
{
    ETGLedgerVoucherTransactionDetailsController controller = new ETGLedgerVoucherTransactionDetailsController();


    if (curExt() == 'y002')
    {

        controller.parmReportName(ssrsReportStr(ETGLedgerVoucherTransactionDetails, PrecisionDesign3));
    }

    else if (curExt() == 'E016')
    {

        controller.parmReportName(ssrsReportStr(ETGLedgerVoucherTransactionDetails, PrecisionDesign4));
    }
    else
    {

        controller.parmReportName(ssrsReportStr(ETGLedgerVoucherTransactionDetails, PrecisionDesign1));
    }

    controller.parmArgs(_args);
    controller.parmShowDialog(true);
    controller.startOperation();
}
